VALUES
  ('retired-7c9828ae-moex-00297', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '有關代履行之敘述，下列何者正確？', '["代履行係對於公法上可代替行為義務不履行之行政執行手段", "代履行之執行機關為行政執行分署", "代履行得採取斷水斷電之方式來執行", "若代履行無效果，應對義務人科處怠金 13730"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00298', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '有關行政規則之敘述，下列何者錯誤？', '["行政規則，係指上級對下級機關為規範機關內部秩序及運作所為之規定", "行政規則，乃係非直接對外發生法規範效力之一般、抽象規定", "屬解釋性規定之行政規則，因僅具內部效力，程序上只需下達下級機關或屬官", "行政規則，亦包括行政機關為行使裁量權而訂定之裁量基準"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00299', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '環保團體對於環境主管機關提出空氣污染問題之陳情，依行政程序法之規定，下列敘述何者正確？', '["人民之陳情，必須具明理由並限於以書面方式提出", "應向其他機關進行陳情者，非該機關即可不予理會", "無論陳情內容為何，一旦受理陳情後應舉行公聽會", "對於業已適當處理並明確回覆後，而仍一再陳情者，得不予處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00300', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於訴願法之敘述，下列何者錯誤？', '["處分機關未告知救濟期間，致相對人遲誤者，如自處分書送達後1年內聲明不服時，視為於法 定期間內所為", "提起訴願逾法定期間者，應為不受理之決定", "訴願人誤向訴願管轄機關以外之機關作不服原行政處分之表示者，應為不受理之決定", "訴願之提起，應自行政處分達到或公告期滿之次日起30日內為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00301', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '有關行政自我拘束原則之敘述，下列何者為錯誤？', '["得自平等原則導出", "只要有行政慣例之存在，即有行政自我拘束原則之適用", "行政機關適用構成要件用語明確之羈束條款時，不適用之", "行政機關有正當理由時，得為與行政先例不一致之決定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00302', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於行政法院對於行政處分之審查，下列敘述何者錯誤？', '["對於具有高度屬人性之評定，得審查是否出於錯誤之事實認定", "對於具有高度屬人性之評定，採取較低密度之審查", "對於具有高度屬人性之評定，得審查作成程序之合法性", "對於具有高度屬人性之評定，得審查其合法性與妥當性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00303', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '關於國家賠償法，下列敘述何者正確？', '["國家負損害賠償責任者，以回復原狀為原則", "賠償請求權之消滅時效期間，自請求權人實際知悉賠償義務機關時起算", "因公共設施之管理有欠缺所生之國家賠償責任，以管理機關有過失為必要", "於請求損害賠償時，法院得依聲請為假處分，命賠償義務機關暫先支付醫療費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7c9828ae-moex-00304', 'retired-7c9828ae', 'retired-7c9828ae-moex-110-3082b5f1', 'sub-retired-7c9828ae-06', NULL, 'single_choice', '依我國釋憲實務，關於土地徵收與徵收補償費之敘述，下列何者錯誤？', '["徵收之目的不限於公用", "補償必須相當，且應儘速發給，否則徵收土地核准案即應失其效力", "土地所有權人因公路穿越其土地之地下，亦得請求徵收地上權", "徵收補償應等同於損害賠償，以填補所受損害及所失利益為範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:09+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "134", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "社會工作"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00001', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-13504c0c', 'sub-retired-7ec62a85-01', NULL, 'single_choice', '下列文句「」中用詞，何者最為妥切？', '["好友已值「從心所欲」之年，是拚搏事業的好時機", "土耳其大地震，死傷人數慘重，令人「忍俊不住」", "王生誤解了李生的好意，慚愧的登門「負荊請罪」", "他們兄弟感情深厚，真是「舉案齊眉」，令人稱羨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00002', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-13504c0c', 'sub-retired-7ec62a85-01', NULL, 'single_choice', '「樹上的花是小說，有枝有幹地攀在縱橫交叉的結構上，那裡面有多層次、多角度 的說不盡的故事。草花是詩，由於矮，像是剛從土裡蹦上來的，一種精粹的、鮮艷 的、凝聚的、集中的美。散文是爬籐花，都有一種走到那裡就開到那裡的渾灑。如 果有什麼花可以稱之為舞台劇的，大概就是曇花了吧。它是一種徹底的時間藝術， 在絲帷的開闔間即生而即死。」 根據上文，下列選項，何者最接近文意？', '["小說是高高在上，像樹上的花必須仰望", "詩則俯拾即是，就像草花一樣隨處可見", "散文必須像爬籐，要旅行才能寫得渾灑", "舞台劇如曇花，在開幕謝幕間展演人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
